import React, { useState, useEffect } from "react";
import DOMPurify from "dompurify";
import "./App.css";

function App() {
  const [githubUser, setGithubUser] = useState("");
  const [leetcodeUser, setLeetcodeUser] = useState("");
  const [linkedinData, setLinkedinData] = useState("");
  const [workExperience, setWorkExperience] = useState([{ title: "", company: "", dates: "", description: "" }]);
  const [education, setEducation] = useState("");
  const [data, setData] = useState(null);
  const [aiOverview, setAiOverview] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");
  const [selectedTemplate, setSelectedTemplate] = useState("ATS-friendly");

  const fetchData = async () => {
    if (!githubUser) {
      setError("Please enter GitHub username");
      return;
    }
    setIsLoading(true);
    setError("");
    try {
      const res = await fetch("http://localhost:4000/api/process-data", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ githubUser, leetcodeUser, workExperience, education, linkedinData }),
      });
      if (!res.ok) throw new Error(await res.text());
      const data = await res.json();
      setData(data);
      setAiOverview(DOMPurify.sanitize(data.summary || `AI Overview for ${githubUser}: ...`));
    } catch (err) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const downloadResumePDF = async () => {
    const res = await fetch("http://localhost:4000/api/export-pdf", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ ...data, template: selectedTemplate, githubUser, education }),
    });
    const blob = await res.blob();
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `${githubUser || "resume"}.pdf`;
    a.click();
  };

  const downloadResumeDOCX = async () => {
    const res = await fetch("http://localhost:4000/api/export-docx", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ ...data, template: selectedTemplate, githubUser, education }),
    });
    const blob = await res.blob();
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `${githubUser || "resume"}.docx`;
    a.click();
  };

  const downloadPortfolioZIP = async () => {
    const res = await fetch("http://localhost:4000/api/export-portfolio", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ ...data, template: selectedTemplate, githubUser, education }),
    });
    const blob = await res.blob();
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `portfolio.zip`;
    a.click();
  };

  useEffect(() => {
    if (data) {
      const html = `
        <div>${getTemplateHTML({ ...data, linkedinData }, selectedTemplate)}</div>
      `;
      const previewDiv = document.getElementById("preview");
      if (previewDiv) {
        previewDiv.innerHTML = DOMPurify.sanitize(html);
      }
    }
  }, [data, selectedTemplate]);

  const getTemplateHTML = (data, template) => {
    // Simplified for preview; backend handles full HTML
    return `
      <h1>${data.githubUser || "Your Name"}'s Resume</h1>
      <p>${data.summary || "Summary placeholder"}</p>
      <h2>Skills</h2><ul>${(data.skills || []).map(s => `<li>${s}</li>`).join("") || "<li>No skills</li>"}</ul>
      <h2>Experience</h2>${(data.workExperience || []).map(exp => `<p><strong>${exp.title} at ${exp.company}</strong> (${exp.dates})<br>${exp.description}</p>`).join("") || "<p>No experience</p>"}
      <h2>Education</h2><p>${data.education || "No education"}</p>
      ${data.leetcode ? `<h2>LeetCode Stats</h2><p>Problems Solved: ${(data.leetcode.submitStats?.acSubmissionNum.find(s => s.difficulty === "All")?.count || 0)}</p><p>Contest Badge: ${data.leetcode.contestBadge?.name || "N/A"}</p>` : ""}
    `;
  };

  const addExperience = () => {
    setWorkExperience([...workExperience, { title: "", company: "", dates: "", description: "" }]);
  };

  const updateExperience = (index, field, value) => {
    const newExperience = [...workExperience];
    newExperience[index][field] = value;
    setWorkExperience(newExperience);
  };

  return (
    <div className="container">
      <h1>Instant Resume Generator</h1>

      <div className="form-group">
        <label>GitHub Username:</label>
        <input
          type="text"
          value={githubUser}
          onChange={(e) => setGithubUser(e.target.value)}
          placeholder="e.g., sugandhatiwari01"
        />
      </div>

      <div className="form-group">
        <label>LeetCode Username:</label>
        <input
          type="text"
          value={leetcodeUser}
          onChange={(e) => setLeetcodeUser(e.target.value)}
          placeholder="e.g., user123 (optional)"
        />
      </div>

      <div className="form-group">
        <label>LinkedIn Data (Manual):</label>
        <textarea
          value={linkedinData}
          onChange={(e) => setLinkedinData(e.target.value)}
          placeholder="Enter experience/education manually (optional)"
        />
      </div>

      <div className="form-group">
        <label>Education:</label>
        <input
          type="text"
          value={education}
          onChange={(e) => setEducation(e.target.value)}
          placeholder="e.g., BS CS, MIT"
        />
      </div>

      <div className="form-group">
        <label>Work Experience:</label>
        {workExperience.map((exp, index) => (
          <div key={index} className="experience-group">
            <div className="experience-row">
              <input
                type="text"
                value={exp.title}
                onChange={(e) => updateExperience(index, "title", e.target.value)}
                placeholder="Title"
              />
              <input
                type="text"
                value={exp.company}
                onChange={(e) => updateExperience(index, "company", e.target.value)}
                placeholder="Company"
              />
              <input
                type="text"
                value={exp.dates}
                onChange={(e) => updateExperience(index, "dates", e.target.value)}
                placeholder="Dates"
              />
            </div>
            <input
              type="text"
              value={exp.description}
              onChange={(e) => updateExperience(index, "description", e.target.value)}
              placeholder="Description"
            />
          </div>
        ))}
        <button onClick={addExperience}>Add Experience</button>
      </div>

      <div className="form-group">
        <label>Template:</label>
        <select value={selectedTemplate} onChange={(e) => setSelectedTemplate(e.target.value)}>
          {["Minimal", "ATS-friendly", "Modern"].map((t) => (
            <option key={t} value={t}>{t}</option>
          ))}
        </select>
      </div>

      <button onClick={fetchData} disabled={isLoading}>
        {isLoading ? "Loading..." : "Fetch Data & Generate Resume"}
      </button>

      {error && <div className="error">{error}</div>}
      {isLoading && <div className="loading">Loading data...</div>}

      {data && (
        <div>
          <div className="preview" id="preview"></div>
          <div className="download-buttons">
            <button onClick={downloadResumePDF}>Download Resume (PDF)</button>
            <button onClick={downloadResumeDOCX}>Download Resume (DOCX)</button>
            <button onClick={downloadPortfolioZIP}>Download Portfolio (ZIP)</button>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
